/**
 * RowPreviewDialog — Renders stored HTML content exactly as it will publish.
 *
 * HTML TRUST POLICY: board_result_batch_rows.content stores trusted internal HTML only,
 * generated by AI via generate-custom-page edge function or edited by authenticated admins.
 * No raw external/user-uploaded HTML enters this path. Preview and publish both use the
 * same content field, ensuring WYSIWYG consistency.
 */
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import type { BatchRow } from './useBatchPipeline';

interface Props {
  row: BatchRow | null;
  open: boolean;
  onClose: () => void;
}

export function RowPreviewDialog({ row, open, onClose }: Props) {
  if (!row) return null;

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            Preview: {row.display_title || row.board_name}
            <Badge variant="outline">{row.word_count} words</Badge>
            {row.workflow_status === 'published' && <Badge className="bg-green-100 text-green-800">Published</Badge>}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4 text-sm">
          {/* SEO meta preview */}
          <div className="bg-muted/50 rounded-lg p-3 space-y-1">
            <p className="text-blue-600 font-medium truncate">{row.meta_title || row.display_title || row.board_name}</p>
            <p className="text-green-700 text-xs">/{row.slug}</p>
            <p className="text-muted-foreground text-xs">{row.meta_description || 'No meta description'}</p>
          </div>

          {/* Content preview — trusted internal HTML */}
          {row.content ? (
            <div
              className="prose prose-sm max-w-none dark:prose-invert border rounded-lg p-6"
              dangerouslySetInnerHTML={{ __html: row.content }}
            />
          ) : (
            <div className="text-center py-12 text-muted-foreground">No content yet — enrich first</div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}
